"""
MKT Context Commentary — 2 Chronicles chapters 32–34
Run: python3 scripts/zc-context-2chronicles-32-34.py

Ch 32: Sennacherib's invasion (701 BCE) — ANE siege warfare, psychological warfare speeches,
       angel-strikes motif; Siloam Tunnel; Babylonian envoy testing.
Ch 33: Manasseh's syncretism under Neo-Assyrian vassalage; unprecedented repentance narrative
       (unique to Chronicles); kānaʿ/"humble" as Chronicler's retribution keyword; Amon contrast.
Ch 34: Josiah's staged reform; dāraš (seek) theological marker in v3; Book of the Law discovery;
       Huldah the prophetess; Deuteronomic covenant renewal.

Key decisions:
- kānaʿ rendered consistently as "humble oneself" — H3665, pivotal for Chronicler's retribution theology
- dāraš: "seek" — H1875, the Chronicler's diagnostic of faithfulness
- "Prayer of Manasseh" deuterocanonical text acknowledged in ch33 notes
- Huldah's consulting acknowledged as historically significant female prophetic authority
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON2 = {
  "32": {
    "1": "<p>&ldquo;After these acts of faithfulness&rdquo; — the Chronicler&rsquo;s structural link is deliberate: Hezekiah&rsquo;s obedience (chs 29&ndash;31) is followed immediately by the Assyrian crisis. In the Chronicler&rsquo;s theology, faithfulness does not guarantee exemption from trial but ensures divine backing within it. The Assyrian campaign of Sennacherib (701 BCE) is independently attested in his own annals (the Taylor Prism / Chicago Prism), which claim tribute from Hezekiah but conspicuously avoid claiming Jerusalem&rsquo;s capture.</p>",
    "2": "<p>Sennacherib invaded Judah in 701 BCE as part of a broader western campaign suppressing the anti-Assyrian coalition. His annals list 46 Judean fortified cities taken before moving against Jerusalem. The Assyrian imperial policy was systematic: reduce outlying fortresses, then besiege the capital. Hezekiah&rsquo;s intelligence about Sennacherib&rsquo;s intentions would have been available from surviving refugees of fallen cities.</p>",
    "3": "<p>Blocking water sources outside the city was standard pre-siege military protocol in the ANE. Depriving the attacking army of water is documented in Mesopotamian siege manuals and strategika of the period. The Chronicler connects this to Hezekiah&rsquo;s famous engineering project &mdash; the Siloam Tunnel (see v30) &mdash; which redirected Gihon spring waters into the city, simultaneously denying the besiegers water and securing the defenders&rsquo; supply.</p>",
    "4": "<p>The Siloam Tunnel inscription (discovered 1880 CE, now in Istanbul) is one of the most important Hebrew epigraphic finds, describing the workers tunneling from both ends and meeting in the middle. The tunnel is 533 meters long, cut through solid rock beneath the city of David. The &ldquo;brook running through the region&rdquo; is the Kidron-area drainage. This verse confirms the Chronicler&rsquo;s awareness of the engineering achievement celebrated more fully in v30.</p>",
    "5": "<p>The phrase &ldquo;rebuilt all the broken-down sections of the wall&rdquo; refers to the Broad Wall excavated by Nahman Avigad in the Jewish Quarter of Jerusalem (1970s), a wide wall segment dated to the late 8th century BCE that appears to incorporate earlier structures. Archaeological evidence confirms a major fortification expansion under Hezekiah, consistent with the expected influx of northern refugees after 722 BCE and preparation for Assyrian attack.</p>",
    "6": "<p>The &ldquo;city gate square&rdquo; (<em>rĕḥôḇ šaʿar hāʿîr</em>) was the primary civic space in ancient Israelite cities &mdash; site of legal proceedings, commerce, and public assembly (Ruth 4:1; 2 Chr 29:4). Hezekiah&rsquo;s speech to the assembled commanders and people follows the classical pre-battle exhortation pattern found across ANE military literature: identify the threat, invoke divine aid, call to courage.</p>",
    "7": "<p>&ldquo;Be strong and courageous&rdquo; (<em>ḥizqû weʾimṣû</em>) is the Mosaic-Deuteronomic commissioning formula given first to Joshua (Deut 31:6-7; Josh 1:6-9). Hezekiah deliberately invokes this register &mdash; the battle belongs to YHWH, not to the king&rsquo;s military competence. The phrase &ldquo;do not be afraid or dismayed&rdquo; (<em>ʾal-tîrĕʾû wĕʾal-tēḥattû</em>) recurs verbatim in the Holy War tradition, framing this confrontation as a sacred contest.</p>",
    "8": "<p>&ldquo;With him is an arm of flesh, but with us is the LORD our God&rdquo; &mdash; the contrast between Assyrian military might and YHWH&rsquo;s power is expressed in the phrase <em>zĕrôaʿ bāśār</em> (arm of flesh). The theology is explicitly anti-trust-in-horses (Isa 31:1-3, also addressed to Hezekiah&rsquo;s Jerusalem). &ldquo;The people were strengthened&rdquo; (<em>wayyissammĕḵû</em>) by Hezekiah&rsquo;s words &mdash; the verb <em>sāmak</em> (lean, rely on) used elsewhere for trust placed in YHWH.</p>",
    "9": "<p>Lachish was the second most fortified city of Judah after Jerusalem. Sennacherib&rsquo;s siege of Lachish is extraordinarily well documented: his own monumental reliefs in the British Museum (Room 10b) depict the assault in meticulous detail &mdash; battering rams, siege ramps, captives impaled, and deportees marching. The Lachish Letters (ostraca found in the gate room) show the panic of the regional commanders. Sennacherib set up his headquarters at Lachish to threaten Jerusalem from a position of demonstrated military dominance.</p>",
    "10": "<p>The Rab-shakeh&rsquo;s speech is a masterpiece of psychological warfare (<em>millḥāmâ nafsît</em> in modern Hebrew, but the concept is ANE). It targets the four potential sources of Judean confidence: (1) military coalition allies, (2) YHWH himself, (3) Egypt, (4) the city&rsquo;s own defenses. The speech is preserved in fuller form in 2 Kings 18-19 and Isaiah 36-37; the Chronicler offers a condensed version focusing on its theological audacity.</p>",
    "11": "<p>The accusation that Hezekiah is inducing starvation by claiming YHWH will deliver is rhetorically designed to turn the population against their own king. The siege of a city often depended on internal morale collapsing before the walls did &mdash; inducing defections, civilian panic, and surrender. The offer of &ldquo;each of you eating from your own vine&rdquo; echoes Assyrian propaganda offering resettlement terms to those who surrender (comparable language in the full 2 Kgs 18 text).</p>",
    "12": "<p>Sennacherib&rsquo;s most sophisticated argument: Hezekiah&rsquo;s cultic reforms (centralization of worship, removal of high places) are reframed as insults to YHWH &mdash; implying the deity is now angry at Hezekiah for reducing his worship sites. This exploits the genuine ambiguity that any Assyrian diplomat might observe: worshippers had been banned from local shrines they previously used. The Chronicler records this as blasphemy, but the rhetorical move would have found receptive ears among those who preferred their local high places.</p>",
    "13": "<p>The claim that no gods of any nation have resisted Assyrian conquest is historically accurate as propaganda: Assyria had destroyed the gods of Hamath, Arpad, Sepharvaim, Samaria. The ANE understanding was that conquered deities were defeated deities &mdash; the victor&rsquo;s god had triumphed over the loser&rsquo;s god. Sennacherib applies this framework to YHWH. What he cannot categorize is that YHWH does not reside in a capturable temple statue.</p>",
    "14": "<p>The rhetorical question &ldquo;who among all the gods&hellip; was able to deliver his people?&rdquo; assumes the ANE framework of divine geography: each god controls a territory and its fate is bound to that territory&rsquo;s fate. The Israelite prophets (especially Isaiah 40-48) directly attack this assumption: YHWH created all nations and uses even Assyria as his instrument; he is not one deity among many subject to the same power dynamics.</p>",
    "15": "<p>The cumulative force of the Rab-shakeh&rsquo;s speech aims at a single conclusion: surrender is the only rational option because YHWH is no more capable of resistance than any other defeated deity. The speech is theologically totalizing &mdash; it offers no category for a god who both permits conquest and remains sovereign over the conqueror. This is precisely what the Isaiah tradition answers: YHWH uses Assyria as &ldquo;the rod of my anger&rdquo; (Isa 10:5) and will discard it in turn.</p>",
    "16": "<p>The Assyrian officials compound the blasphemy with additional verbal attacks on both YHWH and Hezekiah. In the ANE, insulting an enemy&rsquo;s deity before battle was a psychological tactic that also functioned as a ritual provocation &mdash; an invitation for YHWH to demonstrate his power (or, from the Assyrian perspective, his inability to do so). The Chronicler records this as corporate guilt attracting divine response.</p>",
    "17": "<p>The written letters correspond to actual Assyrian diplomatic practice &mdash; formal letters to vassals and enemies were standard instruments of imperial communication. Sennacherib explicitly equates YHWH with &ldquo;the gods of the peoples of the lands&rdquo; (<em>ʾĕlōhê gôyê hāʾărāṣôt</em>), a category he assumes YHWH fits. Isaiah&rsquo;s response to Hezekiah when the letters are displayed (Isa 37:14-20) treats this equation as the central blasphemy requiring divine answer.</p>",
    "18": "<p>Speaking in &ldquo;the Judean language&rdquo; (<em>yĕhûdît</em>) &mdash; Hebrew &mdash; rather than Aramaic (the diplomatic lingua franca of the period) was a deliberate choice to reach the civilian population directly. In 2 Kings 18:26, the Judean officials explicitly request that the Assyrian negotiate in Aramaic (which the officials understood) rather than Hebrew, precisely to prevent the wall-defenders from hearing. Sennacherib&rsquo;s envoy refuses &mdash; the message is meant for the people, not just the government.</p>",
    "19": "<p>The equating of YHWH with &ldquo;the gods of the peoples of the earth, which are the work of human hands&rdquo; is the pivotal theological error the Chronicler highlights. This is the ANE assumption of divine localism and divine materiality &mdash; gods reside in statues, statues can be captured. The Deuteronomic tradition had consistently warned against this confusion (Deut 4:28; Isa 44:9-20). Hezekiah&rsquo;s prayer in Isaiah 37:16-20 directly refutes this: YHWH is &ldquo;the God of all the kingdoms of the earth.&rdquo;</p>",
    "20": "<p>Prayer as the decisive military act is a characteristic Chronicler emphasis. Hezekiah and Isaiah pray together &mdash; the king-prophet partnership that recurs throughout the Chronicler&rsquo;s theology of legitimate kingship. Isaiah&rsquo;s oracle in response (2 Kgs 19:20-34 / Isa 37:21-35, not reproduced here) represents one of the most extended prophetic responses to a military crisis in the OT. The Chronicler condenses but preserves the outcome.</p>",
    "21": "<p>The &ldquo;angel&rdquo; (<em>malʾāk</em>) who struck the Assyrian camp is reported as killing &ldquo;every mighty warrior, commander, and officer.&rdquo; 2 Kings 19:35 specifies 185,000 dead in a single night. The event has generated extensive historical discussion: Herodotus (2.141) mentions a story of mice destroying Assyrian bow-strings near Egypt, possibly a garbled memory of the same campaign; others propose a plague (which the &ldquo;angel of death&rdquo; can represent). Sennacherib&rsquo;s own annals confirm he returned to Nineveh without capturing Jerusalem, but attribute this to tribute payment &mdash; a face-saving claim that does not exclude a military catastrophe.</p><p>Sennacherib&rsquo;s assassination by his own sons (&ldquo;his own bowels&rdquo; in some traditions) while in the temple of his god Nisroch is attested in Assyrian records: he was killed in 681 BCE by his son Arda-Mulissi (identified with the biblical Adrammelech) in a succession crisis. For the Chronicler, this confirms the theological narrative: the blasphemer is destroyed in the very house of his own powerless god.</p>",
    "22": "<p>The triple description of YHWH&rsquo;s action &mdash; &ldquo;saved Hezekiah and the inhabitants of Jerusalem from the hand of Sennacherib&rdquo; and &ldquo;from the hand of all others&rdquo; and &ldquo;he cared for them on every side&rdquo; &mdash; uses the covenant-protection language of the Psalms (e.g. Ps 125:2, &ldquo;the LORD surrounds his people now and forevermore&rdquo;). The deliverance is total and attributed without ambiguity to YHWH alone.</p>",
    "23": "<p>The bringing of &ldquo;gifts to the LORD&rdquo; (<em>minḥâ</em>) and &ldquo;valuable presents to Hezekiah&rdquo; reflects the ANE custom of tribute to victorious powers, here reversed: the nations come to Jerusalem bringing gifts rather than Judah paying tribute to Assyria. This brief note establishes Hezekiah as the recipient of honor from all nations &mdash; a Solomonic reversal that the Chronicler frames as the consequence of YHWH&rsquo;s victory.</p>",
    "24": "<p>Hezekiah&rsquo;s illness and recovery are narrated more briefly than in the parallel (2 Kgs 20:1-11 / Isa 38), where the sundial sign is given in detail. The Chronicler focuses on the theological structure: illness as divine visitation, prayer as the response, and healing as divine answer. The &ldquo;sign&rdquo; (<em>mōpēt</em>) is mentioned without explanation, presupposing audience familiarity with the Isaiah tradition. Hezekiah&rsquo;s illness occurs chronologically before the Assyrian crisis in 2 Kings but is placed after it here &mdash; the Chronicler&rsquo;s thematic arrangement highlights the pride that follows blessing.</p>",
    "25": "<p>&ldquo;His heart was proud&rdquo; (<em>gāḇah libbô</em>) &mdash; the same diagnostic the Chronicler uses for Uzziah&rsquo;s downfall (26:16: <em>ûkᵉḥezqātô gāḇah libbô</em>). Elevation of heart after divine blessing is the recurring danger in the Chronicler&rsquo;s theology of retribution. The divine wrath that comes &ldquo;upon him and upon Judah and Jerusalem&rdquo; implicates the community &mdash; the king&rsquo;s pride has corporate consequences, a principle emphasized throughout Deuteronomy.</p>",
    "26": "<p>Hezekiah&rsquo;s humbling of himself (<em>wayyikkānaʿ Ḥizqiyyāhû ĕbĕgōḇah libbô</em>) uses the verb <em>kānaʿ</em> (H3665) that is central to the Chronicler&rsquo;s theology of divine response: divine wrath is forestalled by corporate humility. The same verb governs Manasseh&rsquo;s repentance (33:12, 19), Josiah&rsquo;s response to the law-scroll (34:27), and negatively Amon&rsquo;s failure (33:23). Here Hezekiah leads Jerusalem in this act, and the wrath &ldquo;did not come upon them in the days of Hezekiah&rdquo; &mdash; retribution deferred by humility, a Deuteronomic pattern.</p>",
    "27": "<p>The inventory of Hezekiah&rsquo;s wealth uses the standard royal treasury formula of the ANE: precious metals, spices, shields, and storehouses (cf. Solomon&rsquo;s treasury descriptions in 2 Chr 9). Archaeological evidence for Judean administrative infrastructure in the late 8th century includes the lmlk (&ldquo;belonging to the king&rdquo;) jar handles found throughout Judah, associated with Hezekiah&rsquo;s administrative reorganization of food storage in preparation for the Assyrian invasion.</p>",
    "28": "<p>Storehouses and stalls for livestock reflect the centralized agricultural administration that supported both the military and the temple economy. The Chronicler&rsquo;s interest in such administrative detail is characteristic &mdash; he consistently shows that faithfulness results in material blessing structured around the temple economy. Hezekiah&rsquo;s wealth is a sign of YHWH&rsquo;s blessing on a faithful king, not mere political achievement.</p>",
    "29": "<p>&ldquo;God had given him great possessions&rdquo; (<em>kî-ʾĕlōhîm nātan lô nĕkāsîm harbēh mĕʾōd</em>) &mdash; the Chronicler explicitly attributes Hezekiah&rsquo;s prosperity to divine gift rather than human achievement. This formula recurs throughout Chronicles as the theological interpretation of royal success: David, Solomon, and the faithful kings all receive wealth as a covenantal benefit, not as independent achievement.</p>",
    "30": "<p>The Siloam Tunnel is identified explicitly here: Hezekiah &ldquo;blocked the upper outlet of the waters of Gihon and channeled them straight down to the west side of the city of David.&rdquo; The Siloam Tunnel inscription (8th century BCE, discovered in the tunnel itself) confirms the engineering feat in contemporary Hebrew: two teams tunneled from opposite ends through 533 meters of bedrock and met in the middle, guided by sound. This is one of the most significant archaeological corroborations of any biblical account.</p>",
    "31": "<p>The episode of the Babylonian envoys is unique to the Chronicler in one crucial detail: &ldquo;God left him to himself, in order to test him and to know all that was in his heart.&rdquo; The parallel (2 Kgs 20:12-19 / Isa 39) records Isaiah&rsquo;s condemnation of Hezekiah for showing the treasury to the Babylonians &mdash; a display that announces future Babylonian spoliation. The Chronicler reframes this as a divine test (<em>lĕnassōtô lādaʿat kol-bĕlibbô</em>) rather than simply a prophetic indictment. The &ldquo;sign&rdquo; (<em>hannipeleʾt</em>) that prompted the embassy is the sundial miracle of 2 Kgs 20:8-11 / Isa 38:7-8. Babylon&rsquo;s interest in the astronomical sign reflects their sophisticated astronomical-astrological culture &mdash; a shadow moving backwards would have been an extraordinary phenomenon worth investigating.</p>",
    "32": "<p>The reference to &ldquo;the vision of Isaiah the prophet son of Amoz&rdquo; (<em>ḥăzôn Yĕšaʿyāhû</em>) acknowledges the prophetic collection as a source document. Isaiah 1:1 designates the book as &ldquo;the vision of Isaiah.&rdquo; The Chronicler&rsquo;s use of external sources &mdash; &ldquo;the book of the kings of Judah and Israel&rdquo; and prophetic collections &mdash; is part of his historiographical method, claiming a documented tradition rather than new composition.</p>",
    "33": "<p>Hezekiah&rsquo;s burial &ldquo;in the upper part of the tombs of the sons of David&rdquo; marks an honor in death: placement above the standard royal tomb area signals distinguished status. &ldquo;All Judah and the inhabitants of Jerusalem honored him at his death&rdquo; uses the same vocabulary as Asa&rsquo;s honored burial (16:14) &mdash; the contrast class being those like Jehoram who died &ldquo;without being desired&rdquo; (21:20). The Chronicler&rsquo;s epitaph system consistently rewards faithfulness with honorable burial and public mourning.</p>"
  },
  "33": {
    "1": "<p>Manasseh reigned fifty-five years &mdash; the longest reign in Judean history, surpassing even the northern dynasty kings. He was twelve years old at accession (born during Hezekiah&rsquo;s extended fifteen years of life, 2 Kgs 20:6) and reigned until c. 642 BCE. His long reign, combined with profound apostasy, means his influence on Judah would have been generational. For the Chronicler, the narrative challenge is acute: how did YHWH tolerate this king so long? The answer is the repentance narrative unique to Chronicles (vv11-13).</p>",
    "2": "<p>&ldquo;The detestable practices of the nations that the LORD drove out before the people of Israel&rdquo; (<em>kĕtôʿăḇōt haggôyim ʾăšer hôrîš YHWH</em>) &mdash; the language echoes the Deuteronomic dispossession narrative (Deut 9:4-5; 18:9-12). Manasseh&rsquo;s sin is not just personal deviance but a reversion to pre-conquest Canaanite practice that was the stated reason for Israel&rsquo;s gift of the land. By adopting these practices, Manasseh threatens the theological basis for Judean occupation.</p>",
    "3": "<p>The rebuilding of high places his father destroyed reverses Hezekiah&rsquo;s entire reform program in a single verse. Baal altars (<em>mizbĕḥôt habĕʿālîm</em>) and Asherah poles (<em>hāʾăšērôt</em>) represented the fertility cult complex of Canaanite religion &mdash; agricultural deities whose worship involved sacred pillars, poles, and (in the Elijah tradition) 450 prophets. The &ldquo;host of heaven&rdquo; (<em>ṣĕḇāʾ haššāmāyim</em>) worship &mdash; astral religion &mdash; was particularly associated with Neo-Assyrian influence: vassals were sometimes expected to adopt Assyrian astral cults as a sign of political submission.</p>",
    "4": "<p>Building altars inside the LORD&rsquo;s house constitutes an unprecedented desecration. The temple was explicitly the place where &ldquo;my name shall be there forever&rdquo; (v7, quoting the foundational promise). Placing altars to foreign deities within the sacred space represents a syncretism that denies YHWH&rsquo;s exclusive claim to the temple precinct. The reference to &ldquo;In Jerusalem shall my name be forever&rdquo; echoes the <em>šēm</em>-theology of the Solomonic dedication (2 Chr 6:5-6) &mdash; Manasseh violates the very covenant that secured the Davidic dynasty.</p>",
    "5": "<p>Both courts (<em>šĕtê ḥaṣrôt bêt YHWH</em>) of the temple &mdash; inner and outer &mdash; receive altars to the host of heaven. Neo-Assyrian religious practice included systematic rooftop and courtyard astral worship. The Assyrian deportation policy sometimes included cultic obligations &mdash; political submission expressed through worship of Assyrian gods. Whether Manasseh&rsquo;s astral cult was politically coerced or voluntarily adopted is debated; the Chronicler presents it as voluntary apostasy.</p>",
    "6": "<p>&ldquo;He burned his sons as offerings in the Valley of Ben-Hinnom&rdquo; (<em>gê-ben-hinnōm</em>) &mdash; the valley south of Jerusalem associated with child sacrifice to Molech (2 Kgs 23:10; Jer 7:31; 32:35). This valley&rsquo;s name (contracted to <em>Gehenna</em> in later Hebrew) became in Second Temple Judaism the standard term for the place of eschatological judgment &mdash; a fire that never went out (Isa 66:24). Jesus uses this term exactly in this Second Temple Jewish sense (Mark 9:43-48). Manasseh&rsquo;s use of this valley for child sacrifice invested it with its gruesome associations.</p><p>Omens, divination (<em>nāḥaš</em>), and sorcery (<em>kāšap</em>) are explicitly condemned in Deuteronomy 18:10-12 as the practices of the dispossessed nations. The use of an <em>ʾôḇ</em> (medium) and <em>yiddĕʿōnî</em> (spiritist) &mdash; consultation of the dead &mdash; was the most severe form of prohibited divination. Saul&rsquo;s consultation of the witch of Endor is the paradigm case (1 Sam 28).</p>",
    "7": "<p>The idol (<em>pesel</em>, the carved image) placed in the house of God echoes the warnings of Deuteronomy 4:15-18 and the second commandment. The Chronicler cites the foundational promise to David and Solomon: &ldquo;In this house and in Jerusalem, which I have chosen out of all the tribes of Israel, I will put my name forever.&rdquo; This promise (equivalent to 2 Chr 6:6 / 7:16) is being violated by the very act of placing another deity&rsquo;s image in YHWH&rsquo;s exclusive dwelling. The <em>šēm</em> theology that identifies YHWH with the Jerusalem temple is directly challenged.</p>",
    "8": "<p>The conditional covenant promise &mdash; YHWH will not remove Israel from the land &ldquo;if only they are careful to do all that I have commanded them, the whole law, statutes, and ordinances given through Moses&rdquo; &mdash; echoes the Deuteronomic covenant structure (Deut 28-30). The repetition of this condition at this point in the narrative prepares for its violation: what follows shows systematic breach of every condition. The Deuteronomic curses will follow with the Babylonian exile, as Jeremiah and the Chronicler both understand.</p>",
    "9": "<p>&ldquo;More evil than the nations that the LORD had destroyed before the people of Israel&rdquo; &mdash; a rhetorical superlative that intensifies Manasseh&rsquo;s guilt beyond any Judean predecessor. The logic of Deuteronomy 9:4-5 is inverted: YHWH drove out the nations for their evil; Manasseh&rsquo;s evil surpasses theirs, threatening the same displacement for Israel. This Deuteronomic logic is explicitly stated in 2 Kings 21:9-14 as the reason for the Babylonian exile.</p>",
    "10": "<p>YHWH &ldquo;spoke to Manasseh and his people, but they would not listen&rdquo; (<em>wayyĕḏabbēr YHWH ʾel-Mĕnaššeh&hellip; wĕlōʾ hiqšîḇû</em>). In the Deuteronomic tradition, not listening to YHWH&rsquo;s word through his prophets is the paradigm sin of Israel (2 Kgs 17:13-14; Jer 7:13-15). The verb <em>hiqšîḇ</em> (give ear, pay attention) appears in Jeremiah&rsquo;s temple sermon as the sin that precedes judgment. The mode of YHWH&rsquo;s speech is not specified &mdash; likely prophetic mediation.</p>",
    "11": "<p>The Assyrian capture of Manasseh is unique to Chronicles &mdash; absent entirely from 2 Kings 21. It is plausible from ANE records: both Esarhaddon (680&ndash;669 BCE) and Ashurbanipal (668&ndash;627 BCE) mention a &ldquo;Manasseh of Judah&rdquo; among western vassals paying tribute. Esarhaddon&rsquo;s Prism B lists Manasseh among 22 kings summoned to Nineveh to provide building materials &mdash; this may be the &ldquo;captivity&rdquo; Chronicles describes. &ldquo;With hooks&rdquo; (<em>baḥōḥîm</em>) refers to metal hooks or rings passed through the nose or lips of captives, common in Assyrian bas-reliefs depicting captured leaders. The humiliation was public and deliberate.</p>",
    "12": "<p>In his distress he &ldquo;sought the favor of the LORD his God&rdquo; (<em>wayḥal ʾet-pĕnê YHWH ʾĕlōhāyw</em>) and &ldquo;humbled himself greatly before the God of his fathers&rdquo; (<em>wayyikkānaʿ mĕʾōd millipnê ʾĕlōhê ʾăḇōtāyw</em>). The verb <em>kānaʿ</em> (H3665 &mdash; humble/submit oneself) is the Chronicler&rsquo;s central retribution-reversal word: it appears in Hezekiah&rsquo;s response (32:26), Josiah&rsquo;s response to the law (34:27), and negatively in Amon&rsquo;s refusal (33:23). Here it governs the most dramatic reversal in the Chronicler&rsquo;s entire history: the worst king finds mercy through genuine humility.</p>",
    "13": "<p>&ldquo;God was moved by his entreaty and heard his plea and brought him back to Jerusalem to his kingdom&rdquo; &mdash; <em>wayyēʿātēr lô</em> (&ldquo;was entreated of him&rdquo;). This divine responsiveness to repentant prayer is a foundational principle established in 2 Chr 7:14. The historical referent is the return from Nineveh to Jerusalem, presumably after providing the required tribute or labor. The theological point is explicit: &ldquo;Then Manasseh knew that the LORD is God&rdquo; &mdash; his captivity becomes the instrument of his conversion, the most extreme application of Deuteronomic curse-for-sin / restoration-for-repentance.</p><p>The deuterocanonical &ldquo;Prayer of Manasseh&rdquo; (found in Greek manuscripts and the Syriac Didascalia) represents the Second Temple community&rsquo;s imaginative reconstruction of what Manasseh prayed in Babylon &mdash; evidence that this Chronicler-unique narrative was significant enough to generate liturgical elaboration.</p>",
    "14": "<p>Manasseh&rsquo;s building program &mdash; an outer wall for the city of David, extending to the Fish Gate &mdash; represents a genuine administrative act consistent with a restored Assyrian vassal expanding Jerusalem&rsquo;s defenses. The Fish Gate is mentioned in Nehemiah 3:3 as part of the northern wall of Jerusalem. Archaeological work in the Ophel area has identified Iron Age IIB wall segments that may correspond to this expansion.</p>",
    "15": "<p>The removal of foreign gods and the idol from the temple reverses v7. The specificity of &ldquo;all the altars he had built on the temple hill and in Jerusalem&rdquo; indicates a systematic dismantling of the entire syncretistic cult infrastructure he had established. This reversal is the covenantal sign of genuine repentance &mdash; not merely internal disposition but structural reform. The Chronicler does not minimize how extensive the dismantling needed to be.</p>",
    "16": "<p>&ldquo;He restored the altar of the LORD&rdquo; (<em>wayyākon ʾet-mizbah YHWH</em>) &mdash; the temple altar, defiled or displaced by Manasseh&rsquo;s earlier alterations, is reestablished as the exclusive locus of sacrifice. Peace offerings (<em>šĕlāmîm</em>) and thank offerings (<em>tôdôt</em>) are the proper post-deliverance sacrifices in the temple system &mdash; offerings that acknowledge YHWH&rsquo;s saving act (Ps 50:14, 23; Ps 107:22). Manasseh&rsquo;s sacrificial practice is brought back into the Mosaic framework.</p>",
    "17": "<p>&ldquo;Nevertheless the people still sacrificed at the high places, though only to the LORD their God&rdquo; &mdash; the qualification &ldquo;only to the LORD&rdquo; is the Chronicler&rsquo;s concession that the popular cult was partially correct in its object but wrong in its location. The centralization of worship at Jerusalem was the distinctively Deuteronomic reform, consistently promoted by faithful kings (Hezekiah, Josiah) and consistently resisted by popular practice. The residual high place worship survives even Manasseh&rsquo;s reformed years.</p>",
    "18": "<p>The reference to &ldquo;his prayer to his God&rdquo; (<em>tĕpillātô ʾel-ʾĕlōhāyw</em>) and &ldquo;the words of the seers who spoke to him in the name of the LORD&rdquo; points to sources the Chronicler cites but that have not survived: &ldquo;the records of the kings of Israel&rdquo; and a separate Manasseh source. The deuterocanonical &ldquo;Prayer of Manasseh&rdquo; represents a later tradition filling this gap &mdash; indicating the Chronicler&rsquo;s reference was understood by his successors as pointing to a real prayer document.</p>",
    "19": "<p>&ldquo;His prayer, how God received his entreaty (<em>wayye&#x27;āter lô</em>), all his sins and unfaithfulness, and the sites where he built high places and set up Asherah poles and idols before he humbled himself&rdquo; &mdash; the summary emphasizes that the full record of sin was preserved alongside the repentance. The Chronicler&rsquo;s theology does not erase the sin when repentance occurs but frames both together: sin recorded, repentance recorded, forgiveness enacted. The source document is identified as &ldquo;the records of the seers&rdquo; (<em>diḇrê ḥôzāyw</em> &mdash; the prophetic annals).</p>",
    "20": "<p>Manasseh&rsquo;s burial &ldquo;in his own house&rdquo; &mdash; the garden of Uzza, according to 2 Kings 21:18 &mdash; rather than in the royal tombs may indicate some residual ambiguity about his legacy, or it may reflect the full state of the royal tombs. The Chronicler records no epitaph of honor or dishonor for Manasseh, in contrast to the evaluative formulae for other kings.</p>",
    "21": "<p>Amon&rsquo;s two-year reign (c. 642&ndash;640 BCE) mirrors his father&rsquo;s pattern in its early phase &mdash; he does &ldquo;what was evil in the sight of the LORD, as his father Manasseh had done&rdquo; &mdash; but misses the defining feature: Manasseh&rsquo;s repentance. The Chronicler&rsquo;s compressed treatment signals that Amon&rsquo;s brief reign warrants no extended analysis; his theological failure and political fate are stated efficiently.</p>",
    "22": "<p>Amon &ldquo;sacrificed to all the carved images his father Manasseh had made&rdquo; &mdash; reverting to the pre-repentance Manasseh cult. This detail is significant: Manasseh&rsquo;s reforms had dismantled the cult infrastructure (v15), but apparently the objects themselves survived or were rebuilt. Amon represents the fragility of reform: personal repentance by a king does not automatically transform the culture, and the next generation may revert.</p>",
    "23": "<p>&ldquo;He did not humble himself before the LORD as his father Manasseh had humbled himself&rdquo; (<em>lōʾ niknāʿ millipnê YHWH kĕhikkānaʿ Mĕnaššeh ʾāḇîw</em>) &mdash; the <em>kānaʿ</em> vocabulary appears twice in a single verse, making Amon&rsquo;s failure to follow his father&rsquo;s repentance the theological indictment. The phrase &ldquo;but Amon incurred more and more guilt&rdquo; (<em>kî hûʾ ʾĀmôn hirbâ ʾāšmâ</em>) uses <em>ʾāšmâ</em> (guilt, culpability) &mdash; the same word that triggers the retribution mechanism throughout Chronicles. Amon knew his father had repented and chose not to.</p>",
    "24": "<p>Amon&rsquo;s assassination &ldquo;in his house&rdquo; by his own servants recalls the pattern of palace conspiracies in the Divided Monarchy period. The Chronicler does not specify the motive &mdash; political, religious, or personal grievance. Palace coups were not rare in the ancient Near East, and Judah experienced several (Joash murdered by servants, 24:25; Amaziah also, 25:27). The brevity of the account signals this is merely the mechanical consequence of his apostasy.</p>",
    "25": "<p>&ldquo;The people of the land&rdquo; (<em>ʿam hāʾāreṣ</em>) who executed the assassins and installed Josiah represents an important socio-political institution in Judean history. This group &mdash; likely the landed aristocracy or a broader assembly of free landholders &mdash; appears at key transitions: they installed Joash (23:20-21), killed Amaziah&rsquo;s assassins, and here both execute the conspirators and crown the eight-year-old Josiah. They represent a form of popular legitimacy distinct from palace politics, functioning as a check on purely court-based power.</p>"
  },
  "34": {
    "1": "<p>Josiah was eight years old at accession (c. 640 BCE) and reigned thirty-one years until 609 BCE when he died at Megiddo. His reign is the last great reform before the Babylonian exile. The Chronicler&rsquo;s treatment of Josiah is parallel to his treatment of Hezekiah &mdash; both are faithful kings who inherit corrupted kingdoms and implement comprehensive reforms. The length of the reign (31 years) is notable given his young accession age.</p>",
    "2": "<p>&ldquo;Walking in the ways of his ancestor David&rdquo; (<em>wēyyēlek bĕdarkê dāwîd ʾāḇîw</em>) is the Chronicler&rsquo;s highest royal evaluation, reserved for Asa (2 Chr 14:2), Hezekiah (2 Chr 29:2), and Josiah. &ldquo;Not turning aside to the right or to the left&rdquo; is the Deuteronomic formula for complete obedience to Torah (Deut 5:32; 17:11; Josh 1:7). The phrase frames Josiah as the ideal Deuteronomic king of Deuteronomy 17:18-20, who reads the law and follows it precisely.</p>",
    "3": "<p>The Chronicler provides a staged timeline for Josiah&rsquo;s reform absent from 2 Kings: (1) eighth year of reign (age 16) &mdash; &ldquo;he began to seek the God of his ancestor David&rdquo; (<em>ḥēl lidroš lēʾlōhê dāwîd ʾāḇîw</em>); (2) twelfth year (age 20) &mdash; &ldquo;he began to purge Judah and Jerusalem.&rdquo; The verb <em>dāraš</em> (H1875 &mdash; &ldquo;seek&rdquo;) is the Chronicler&rsquo;s theological diagnostic throughout 2 Chronicles: it marked Asa (14:4), Jehoshaphat (17:3-4), Uzziah (26:5), and negatively Ahaz (not seeking). Josiah&rsquo;s seeking of God is the personal foundation from which the public reform grows.</p>",
    "4": "<p>The demolition of Baal altars (<em>mizbĕḥôt habĕʿālîm</em>) and incense altars (<em>ḥammānîm</em>) is described with concrete actions: they were demolished in his presence, cut down, ground to powder, and scattered. The <em>ḥammānîm</em> (incense altars) are mentioned in Leviticus 26:30 and Isaiah 17:8 and 27:9 as idolatrous objects to be destroyed; the precise identification &mdash; possibly solar cult incense burners &mdash; is debated among archaeologists. Several small incense altars from the Iron Age II have been excavated in Judah and represent the material culture being destroyed here.</p>",
    "5": "<p>Burning the bones of priests on their own altars is the most extreme form of cultic defilement in the ANE: it rendered the altar permanently impure, preventing any future sacrifice. This practice is prophesied in 1 Kings 13:2 against Jeroboam&rsquo;s altar at Bethel (&ldquo;on you they shall burn human bones&rdquo;), and Josiah&rsquo;s action at Bethel is the fulfillment (2 Kgs 23:16). The Chronicler&rsquo;s mention of this indicates the radical irreversibility of Josiah&rsquo;s purge.</p>",
    "6": "<p>Josiah&rsquo;s reform extends into the northern territories &mdash; Manasseh, Ephraim, Simeon, and Naphtali. This is significant: after the fall of Samaria in 722 BCE, much of the north was depopulated and the territory was theoretically available to a strong Judean king. The Assyrian empire was weakening in the late 7th century, and Josiah may have effectively controlled these territories. The Chronicler presents the reform as pan-Israelite restoration &mdash; the northern tribes are implicitly re-gathered under Davidic leadership.</p>",
    "7": "<p>The summary of the purge uses the vocabulary of total annihilation applied to idols: altars cut down (<em>nātaṣ</em>), Asherah poles chopped up (<em>kārat</em>), carved images ground to powder (<em>dāqaq</em>), incense altars cut down (<em>gādaʿ</em>) throughout all Israel. The thoroughness mirrors the Holy War vocabulary applied to Canaanite cult objects in Deuteronomy 7:5 and 12:3. For Josiah, restoring covenant faithfulness requires the same total destruction of false worship that the conquest had originally mandated.</p>",
    "8": "<p>The eighteenth year of Josiah&rsquo;s reign (c. 622 BCE) marks the beginning of the temple repair project that will unexpectedly yield the law-scroll discovery. The Chronicler introduces this project with a delegation: Shaphan the secretary, Maaseiah the city governor, and Joah the recorder. Shaphan becomes a pivotal figure &mdash; his family (his son Ahikam, his grandson Gedaliah) will be crucial to Jeremiah&rsquo;s preservation and to the post-fall administration of Judah.</p>",
    "9": "<p>The money collected from &ldquo;Manasseh, Ephraim, and all the remnant of Israel and from all Judah and Benjamin and the inhabitants of Jerusalem&rdquo; suggests a pan-Israelite offering for the temple &mdash; even northern territories contributing to the Jerusalem sanctuary. This is the Chronicler&rsquo;s consistent vision of the unified people of God gathered around the Davidic-Levitical temple. The Levites as temple-tax collectors appear in 2 Chronicles 24:5-6 (the Joash temple repair) &mdash; the Josiah project follows the same institutional pattern.</p>",
    "10": "<p>The workmen assigned to oversee the house of the LORD are given the money to pay skilled laborers. The pattern of temple repair funding through direct labor contracts recurs in Chronicles (cf. 2 Chr 24:12-13 under Joash). The system bypasses a central treasury and puts the money directly into construction, which the Chronicler notes in v11 as consistent with its purpose.</p>",
    "11": "<p>Craftsmen and builders use the funds for &ldquo;quarried stone and timber for joinery.&rdquo; The specification &ldquo;beams for the buildings that the kings of Judah had neglected&rdquo; (<em>ʾăšer hizmîlû malkê yĕhûdâ</em>) &mdash; neglected or let go to ruin &mdash; indicates the physical deterioration of the temple under Manasseh and Amon was severe. The temple&rsquo;s structural condition becomes a metaphor for the spiritual condition of the kingdom: neglect under apostasy requires active repair under faithfulness.</p>",
    "12": "<p>The supervisors Jahath and Obadiah (from Merari) and Zechariah and Meshullam (from Kohath) represent the Levitical organization of the work. The Chronicler&rsquo;s interest in proper Levitical oversight of the temple economy is consistent: temple work is sacred and must be administered by the designated clan structure established under David (1 Chr 23-26). &ldquo;All who were skilled in musical instruments&rdquo; adding to the supervisors suggests the Levitical singers were involved in the project administration, not just worship.</p>",
    "13": "<p>The administrative detail &mdash; Levites directing burden-bearers, supervising all work in every kind of service, with scribes and officials and gatekeepers &mdash; reflects the complex bureaucratic organization of a major construction project. The Levitical temple administration that David organized (1 Chr 23-27) is here functioning as the Chronicler envisioned it: the Levites as the administrative backbone of the national religious life, not merely cultic performers.</p>",
    "14": "<p>&ldquo;Hilkiah the priest found the book of the law of the LORD given through Moses&rdquo; (<em>sēper tôrat YHWH bĕyad Mōšeh</em>) &mdash; the discovery of the <em>sēper hattôrâ</em> is one of the most debated events in Old Testament historiography. The prevailing scholarly view identifies this scroll with Deuteronomy (or a proto-Deuteronomy), noting that: (1) the curses Josiah fears (v24) match Deuteronomy 28; (2) the covenant renewal that follows (vv29-33) matches Deuteronomy&rsquo;s covenant format; (3) the reform measures including centralization match Deuteronomic law. How the scroll came to be in the temple &mdash; deposited there for safekeeping, hidden during Manasseh&rsquo;s reign, or genuinely lost &mdash; is unknown.</p>",
    "15": "<p>Hilkiah&rsquo;s report to Shaphan the secretary follows normal bureaucratic procedure: the high priest communicates to the royal secretary, who will transmit to the king. The scroll is described as &ldquo;a book&rdquo; (<em>sēper</em>) and then as &ldquo;the book of the law&rdquo; &mdash; a distinction that may indicate Hilkiah recognized it as specifically the Mosaic Torah scroll, not merely an administrative document. The physical finding during construction work (rather than in an archive) may indicate it had been stored in a wall or floor space.</p>",
    "16": "<p>Shaphan reports both the completion of the practical administrative tasks (&ldquo;everything committed to your servants they are doing&rdquo;) and the scroll discovery, treating them as two items in his briefing to the king. The scroll is &ldquo;a book&rdquo; in Shaphan&rsquo;s initial description; it becomes &ldquo;the book&rdquo; after Shaphan reads it aloud. The oral reading before the king represents the standard procedure for presenting official documents &mdash; royal archives were read to kings who heard rather than personally reading documents.</p>",
    "17": "<p>The temple-money accounting &mdash; collected, delivered to overseers, paid to workers &mdash; is summarized as properly completed before the scroll discovery is reported. The Chronicler presents the administrative integrity of the project as the backdrop for the spiritual crisis about to unfold: a king whose practical faithfulness in temple repair led to the discovery of the very law that revealed how far Israel had fallen.</p>",
    "18": "<p>The public reading of the scroll before the king &mdash; <em>wayyiqrāʾhû Šāpān lipnê hammelek</em> &mdash; is the pivotal moment. The reading of the Torah before the king echoes Deuteronomy 17:18-20&rsquo;s command that the king copy the law, read it, and follow it all his life. The king&rsquo;s response to hearing the law read distinguishes the faithful king from the apostate: Josiah tears his clothes; Jehoiakim will cut Jeremiah&rsquo;s scroll with a penknife and burn it (Jer 36:23-24).</p>",
    "19": "<p>Josiah tears his clothes (<em>wayyiqraʿ ʾet-bĕgādāyw</em>) &mdash; the standard expression of mourning and alarm in the ANE (Gen 37:29; 2 Sam 1:11; 2 Kgs 22:11). The tearing of clothes upon hearing the law signals that Josiah heard the curses of Deuteronomy 28 and recognized their application to Israel&rsquo;s actual condition. This is precisely the response the Deuteronomic narrator approves: the covenant mediator who genuinely hears the covenantal obligations and their threatened consequences.</p>",
    "20": "<p>The delegation sent to inquire of YHWH includes Hilkiah the priest, Ahikam son of Shaphan (who will later protect Jeremiah, Jer 26:24), Abdon son of Micah, Shaphan the secretary, and Asaiah the king&rsquo;s servant. The choice to inquire of a prophet rather than simply act on the written text reflects the continuing prophetic institution as the living voice that interprets Torah for the current situation. Josiah does not presume he can read the text and apply it without prophetic guidance.</p>",
    "21": "<p>&ldquo;Go, inquire of the LORD for me and for all who remain in Israel and Judah concerning the words of the book that has been found&rdquo; &mdash; the scope is pan-Israelite: &ldquo;all who remain in Israel and Judah&rdquo; includes the northern population living under Josiah&rsquo;s expanded control. Josiah&rsquo;s identification of &ldquo;great is the wrath of the LORD that is poured out on us, because our fathers have not kept the word of the LORD&rdquo; shows he has already understood the text as describing Judah&rsquo;s actual situation &mdash; the Deuteronomic curses are in effect.</p>",
    "22": "<p>Huldah the prophetess, wife of Shallum son of Tokhath &mdash; she is stationed &ldquo;in Jerusalem in the Second Quarter&rdquo; (<em>bammišneh</em>), the new urban district north or northwest of the original city, developed in the 8th&ndash;7th centuries (cf. Zeph 1:10 which mentions the Maktesh area and the &ldquo;Second Quarter&rdquo;). The delegation goes to Huldah even though Jeremiah and Zephaniah were active prophets in Jerusalem at this time. Possible explanations: her proximity, her authority in cultic-legal matters, or her specific association with the temple community (her husband was a temple official). Huldah is one of four named female prophets in the OT (Miriam, Deborah, Huldah, Noadiah).</p>",
    "23": "<p>&ldquo;Thus says the LORD, the God of Israel&rdquo; (<em>koh ʾāmar YHWH ʾĕlōhê Yiśrāʾēl</em>) &mdash; Huldah&rsquo;s oracle uses the standard prophetic messenger formula, establishing her as an authorized spokesperson for YHWH. The formula itself claims institutional prophetic authority equal to any male prophet. Her oracle has two parts: judgment on Jerusalem (vv24-25) and mercy for Josiah personally (vv26-28). This structural distinction &mdash; the judgment for the nation is unalterable; the mercy for the individual who humbles himself is secure &mdash; reflects the Chronicler&rsquo;s core theology.</p>",
    "24": "<p>&ldquo;I will bring disaster upon this place and upon its inhabitants &mdash; all the curses written in the book that was read before the king of Judah&rdquo; (<em>kol-haqqĕlālôt hakkĕtûḇôt ʾal-hassēper ʾăšer qārĕʾû&hellip;</em>) &mdash; the explicit identification of the scroll&rsquo;s curses as the content of the coming disaster. This is the Deuteronomic curse-fulfillment mechanism of Deuteronomy 28:15-68: Israel&rsquo;s persistent disobedience triggers the written consequences. The judgment is not arbitrary; it was covenantally announced centuries before and the nation had walked into it progressively through Manasseh&rsquo;s generation.</p>",
    "25": "<p>The three-part description of the sin &mdash; &ldquo;they have abandoned me&rdquo; (<em>ʿazāḇûnî</em>), &ldquo;made offerings to other gods&rdquo; (<em>wayyĕqaṭṭĕrû lēʾlōhîm ʾăḥērîm</em>), and &ldquo;provoking me to anger with all the works of their hands&rdquo; (<em>lĕhaḵʿîsênî bĕkol maʿăśēh yĕdêhem</em>) &mdash; matches the indictment formulae of the Deuteronomic History (1 Kgs 14:9; 2 Kgs 22:17). &ldquo;Works of their hands&rdquo; is the standard Deuteronomic phrase for idols, emphasizing their manufactured rather than divine origin. The combination &ldquo;provoke to anger&rdquo; (<em>kiʿas</em>) is a characteristically Deuteronomic description of idolatry&rsquo;s effect on YHWH.</p>",
    "26": "<p>The second part of Huldah&rsquo;s oracle shifts to Josiah personally: &ldquo;Thus says the LORD, the God of Israel&rdquo; repeated, this time addressed to &ldquo;the king of Judah who sent you to inquire of the LORD.&rdquo; The structural distinction in v26-28 is between corporate judgment (national, inevitable) and personal mercy (conditional on the king&rsquo;s response). This distinction runs through the Chronicler&rsquo;s entire theology: community consequences flow from corporate apostasy, but individuals who genuinely seek YHWH find a different personal outcome.</p>",
    "27": "<p>&ldquo;Because your heart was tender and you humbled yourself before God when you heard his words&rdquo; (<em>yaʿan rāk lĕḇāḇĕkā wattikkānaʿ millipnê ʾĕlōhîm&hellip;</em>) &mdash; the three elements of Josiah&rsquo;s favorable assessment: tender heart (<em>rāk lēḇ</em>), self-humbling (<em>kānaʿ</em> &mdash; H3665, the Chronicler&rsquo;s key retribution-reversal word), and the specific trigger (hearing the words against this place and its inhabitants). All three elements are connected: hearing led to humbling, and humbling is the covenantal disposition that activates mercy. The word <em>kānaʿ</em> here joins Hezekiah (32:26), Manasseh (33:12, 19, 23), and negatively Amon, forming the Chronicler&rsquo;s central diagnostic of royal faithfulness in these chapters.</p>",
    "28": "<p>&ldquo;I will gather you to your fathers, and you will be gathered to your grave in peace&rdquo; (<em>nĕʾāsaptā ʾel-qiḇrōtêkā bĕšālôm</em>) &mdash; the promise of a peaceful death is specifically a personal mercy, not a promise that Jerusalem will avoid judgment. Josiah does not personally witness the Babylonian destruction (he dies at Megiddo in 609 BCE). The phrase &ldquo;your eyes shall not see all the disaster that I will bring upon this place&rdquo; is the merciful qualification: he is spared the sight of what his faithfulness could not permanently prevent. The corporate judgment cannot be reversed; the individual&rsquo;s eyes can be spared it.</p>",
    "29": "<p>The covenant renewal assembly begins with Josiah summoning &ldquo;all the elders of Judah and Jerusalem&rdquo; (<em>kol-ziqnê yĕhûdâ wîrûšālaim</em>). The Deuteronomic covenant-renewal format (Deut 31:9-13; Josh 24) required the assembly of the entire covenant community before the reading and re-affirmation of the Torah. This institutional pattern &mdash; king, elders, people, priests, Levites &mdash; structures the ceremony in the manner of the Mosaic and Joshuanic precedents.</p>",
    "30": "<p>The full assembly at the temple &mdash; men, women, and children; priests and Levites and all the people, small and great (<em>miqqāṭōn wĕʿad-gādôl</em>) &mdash; mirrors the language of Deuteronomy 29:10-11 (&ldquo;you are standing today, all of you, before the LORD your God: the heads of your tribes, your elders, and your officers, all the men of Israel, your little ones, your wives&rdquo;). The reading of the covenant &ldquo;in their hearing&rdquo; (<em>bĕʾoznêhem</em>) echoes the Mosaic reading of the book of the covenant (Exod 24:7; Deut 31:11). The covenant renewal reconstitutes Israel as the covenant people at a critical moment before judgment.</p>",
    "31": "<p>&ldquo;The king stood in his place and made a covenant before the LORD&rdquo; (<em>wayyaʿămōd hammelek ʿal-ʿomĕdô wayyikrōt habĕrît&hellip;</em>) &mdash; <em>kārat bĕrît</em> (cut a covenant) is the foundational covenant-making formula throughout the OT. The Josiah covenant renewal is described in three components: &ldquo;to follow the LORD and to keep his commandments, testimonies, and statutes with all his heart and all his soul.&rdquo; The phrase &ldquo;with all his heart and all his soul&rdquo; (<em>bĕkol-lĕḇāḇô ûḇĕkol-napšô</em>) is Deuteronomy&rsquo;s Shema-love formula (Deut 6:5; 10:12) &mdash; the covenantal response to YHWH&rsquo;s election.</p>",
    "32": "<p>&ldquo;He required all who were present in Jerusalem and Benjamin to stand to it&rdquo; (<em>wayyaʿămēd kol-hannimṣāʾ bîrûšālaim ûḇinyāmîn</em>) &mdash; the covenant obligation is made corporate and binding. The &ldquo;inhabitants of Jerusalem acted according to the covenant of God, the God of their fathers&rdquo; completes the covenant formula: the people are the other party, and their standing to the covenant is the covenantal response to the king&rsquo;s initiative. This mirrors the Mosaic structure of Sinai: Moses reads, the people hear, the people respond.</p>",
    "33": "<p>&ldquo;Josiah removed all the abominations from all the territories belonging to the people of Israel and required all who were present in Israel to serve the LORD their God&rdquo; &mdash; the territorial scope (all Israel) and the active enforcement of worship (requiring service) confirms the Chronicler&rsquo;s vision of the Josiah reform as a pan-Israelite restoration. &ldquo;All his days they did not turn aside from following the LORD, the God of their fathers&rdquo; &mdash; the Chronicler&rsquo;s closing evaluation is unqualified: under Josiah, the entire covenant community maintained YHWH-only worship. This is the last unambiguous moment of national covenant faithfulness before the Babylonian period.</p>"
  }
}

def main():
    c = load_comm('mkt-context', '2chronicles')
    merge_comm(c, CHRON2)
    save_comm('mkt-context', '2chronicles', c)
    count = sum(len(v) for v in CHRON2.values())
    print(f'2chronicles mkt-context: wrote {count} verses for ch 32-34')

if __name__ == '__main__':
    main()
